{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOgnOSXIy4gRy+Xi+Qy1hZU"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":11,"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"zbuLTSPi0Fxz","executionInfo":{"status":"ok","timestamp":1778182308635,"user_tz":180,"elapsed":12519,"user":{"displayName":"BEATRIZ PRADO SOCHE","userId":"09824196591559439548"}},"outputId":"4d504003-d9f8-4fb0-88fc-99fd9938344c"},"outputs":[{"output_type":"stream","name":"stdout","text":["Welcome to Tic Tac Toe!\n","You are 'O' and the AI is 'X'\n","Enter positions (0-8) as shown below:\n","0 | 1 | 2\n","---------\n","3 | 4 | 5\n","---------\n","6 | 7 | 8\n","\n","\n","  |   |  \n","---------\n","  |   |  \n","---------\n","  |   |  \n","\n","AI's turn...\n","X |   |  \n","---------\n","  |   |  \n","---------\n","  |   |  \n","\n","Your turn (0-8): 4\n","X |   |  \n","---------\n","  | O |  \n","---------\n","  |   |  \n","\n","AI's turn...\n","X | X |  \n","---------\n","  | O |  \n","---------\n","  |   |  \n","\n","Your turn (0-8): 2\n","X | X | O\n","---------\n","  | O |  \n","---------\n","  |   |  \n","\n","AI's turn...\n","X | X | O\n","---------\n","  | O |  \n","---------\n","X |   |  \n","\n","Your turn (0-8): 5\n","X | X | O\n","---------\n","  | O | O\n","---------\n","X |   |  \n","\n","AI's turn...\n","X | X | O\n","---------\n","X | O | O\n","---------\n","X |   |  \n","\n","AI wins!\n"]}],"source":["class TicTacToe:\n","    def __init__(self):\n","        # Initialize empty board (using ' ' for empty squares)\n","        self.board = [\" \" for _ in range(9)]\n","        self.human_player = \"O\"\n","        self.ai_player = \"X\"\n","\n","    def print_board(self):\n","        \"\"\"Print the current state of the board\"\"\"\n","        for i in range(0, 9, 3):\n","            print(f\"{self.board[i]} | {self.board[i+1]} | {self.board[i+2]}\")\n","            if i < 6:\n","                print(\"---------\")\n","\n","    def available_moves(self):\n","        \"\"\"Returns list of available moves (indices of empty squares)\"\"\"\n","        return [i for i, spot in enumerate(self.board) if spot == \" \"]\n","\n","    def make_move(self, position, player):\n","        \"\"\"Make a move on the board\"\"\"\n","        if self.board[position] == \" \":\n","            self.board[position] = player\n","            return True\n","        return False\n","\n","    def check_winner(self):\n","        \"\"\"Check if there's a winner. Returns winner symbol or None\"\"\"\n","        # Check rows\n","        for i in range(0, 9, 3):\n","            if self.board[i] == self.board[i + 1] == self.board[i + 2] != \" \":\n","                return self.board[i]\n","\n","        # Check columns\n","        for i in range(3):\n","            if self.board[i] == self.board[i + 3] == self.board[i + 6] != \" \":\n","                return self.board[i]\n","\n","        # Check diagonals\n","        if self.board[0] == self.board[4] == self.board[8] != \" \":\n","            return self.board[0]\n","        if self.board[2] == self.board[4] == self.board[6] != \" \":\n","            return self.board[2]\n","\n","        return None\n","\n","    def is_board_full(self):\n","        \"\"\"Check if the board is full\"\"\"\n","        return \" \" not in self.board\n","\n","    def game_over(self):\n","        \"\"\"Check if the game is over\"\"\"\n","        return self.check_winner() is not None or self.is_board_full()\n","\n","    def minimax(self, depth, is_maximizing):\n","        \"\"\"\n","        Minimax algorithm implementation\n","        Returns the best score possible for the current board state\n","        \"\"\"\n","        # Base cases\n","        winner = self.check_winner()\n","        if winner == self.ai_player:\n","            return 1\n","        if winner == self.human_player:\n","            return -1\n","        if self.is_board_full():\n","            return 0\n","\n","        # if it is the maximizing player's turn (AI), we want to maximize the score\n","        if is_maximizing:\n","            best_score = float(\"-inf\")\n","            for move in self.available_moves():\n","                # Make a calculating move\n","                self.board[move] = self.ai_player\n","                # Recursively call minimax with the next depth and the minimizing player\n","                score = self.minimax(depth + 1, False)\n","                # Reset the move\n","                self.board[move] = \" \"\n","                # Update the best score\n","                best_score = max(score, best_score)\n","            return best_score\n","        else:\n","            # if it is the minimizing player's turn (human), we want to minimize the score\n","            best_score = float(\"inf\")\n","            for move in self.available_moves():\n","                # Make a calculating move\n","                self.board[move] = self.human_player\n","                # Recursively call minimax with the next depth and the maximizing player\n","                score = self.minimax(depth + 1, True)\n","                # Reset the move\n","                self.board[move] = \" \"\n","                # Update the best score\n","                best_score = min(score, best_score)\n","            return best_score\n","\n","    def get_best_move(self):\n","        \"\"\"Find the best move for AI using minimax\"\"\"\n","        best_score = float(\"-inf\")\n","        best_move = None\n","\n","        for move in self.available_moves():\n","            # Make a calculating move\n","            self.board[move] = self.ai_player\n","            # Recursively call minimax with the next depth and the minimizing player\n","            score = self.minimax(0, False)\n","            # Reset the move\n","            self.board[move] = \" \"\n","\n","            # Update the best score\n","            if score > best_score:\n","                best_score = score\n","                best_move = move\n","\n","        return best_move\n","\n","    def play_game(self):\n","        \"\"\"Main game loop\"\"\"\n","        print(\"Welcome to Tic Tac Toe!\")\n","        print(\"You are 'O' and the AI is 'X'\")\n","        print(\"Enter positions (0-8) as shown below:\")\n","        print(\"0 | 1 | 2\")\n","        print(\"---------\")\n","        print(\"3 | 4 | 5\")\n","        print(\"---------\")\n","        print(\"6 | 7 | 8\")\n","        print(\"\\n\")\n","\n","        # Randomly decide who goes first\n","        import random\n","\n","        ai_turn = random.choice([True, False])\n","\n","        while not self.game_over():\n","            self.print_board()\n","\n","            if ai_turn:\n","                print(\"\\nAI's turn...\")\n","                move = self.get_best_move()\n","                self.make_move(move, self.ai_player)\n","            else:\n","                while True:\n","                    try:\n","                        move = int(input(\"\\nYour turn (0-8): \"))\n","                        if 0 <= move <= 8 and self.make_move(move, self.human_player):\n","                            break\n","                        else:\n","                            print(\"Invalid move! Try again.\")\n","                    except ValueError:\n","                        print(\"Please enter a number between 0 and 8!\")\n","\n","            ai_turn = not ai_turn\n","\n","        # Game over\n","        self.print_board()\n","        winner = self.check_winner()\n","        if winner == self.ai_player:\n","            print(\"\\nAI wins!\")\n","        elif winner == self.human_player:\n","            print(\"\\nCongratulations! You win!\")\n","        else:\n","            print(\"\\nIt's a tie!\")\n","\n","\n","# Start the game\n","if __name__ == \"__main__\":\n","    game = TicTacToe()\n","    game.play_game()"]}]}